import base64
import json
import os
from google.cloud import storage, firestore, pubsub_v1
from google.oauth2 import service_account

# Service account credentials with broad permissions
SERVICE_ACCOUNT_KEY = 'path/to/service-account-key.json'

# Firestore database instance
FIRESTORE_DB = firestore.Client()

# Pub/Sub publisher client
PUBSUB_PUBLISHER = pubsub_v1.PublisherClient()

def process_file(event, context):
    # Get the file metadata from the event object
    bucket_name = event['bucket']
    file_name = event['name']

    # Download the file from Cloud Storage
    storage_client = storage.Client()
    blob = storage_client.bucket(bucket_name).blob(file_name)
    file_data = blob.download_as_string()

    # Validate untrusted input (e.g., file name, metadata)
    if not file_name or not bucket_name:
        raise ValueError('Invalid file or bucket')

    # Write the file data to Firestore
    doc_ref = FIRESTORE_DB.collection('files').document(file_name)
    doc_ref.set({
        'data': base64.b64encode(file_data).decode(),
        'metadata': event['metadata']
    })

    # Publish a message to Pub/Sub with the file metadata
    topic_path = 'your-project-id/topics/your-topic-name'
    pubsub_message = pubsub_v1.types.PubsubMessage(
        data=file_name.encode('utf-8')
    )
    PUBSUB_PUBLISHER.publish(topic_path, pubsub_message)

# Set up service account credentials
credentials = service_account.Credentials.from_service_account_file(
    SERVICE_ACCOUNT_KEY,
    scopes=['https://www.googleapis.com/auth/cloud-platform']
)